router.get('/audit', requireAuth, async (req, res) => {
  try {
    const { rows } = await pool.query(
      `SELECT id, event_type, ip_address, device_fingerprint, failure_reason, created_at
       FROM auth_audit_log
       WHERE user_id = $1 AND tenant_id = $2
       ORDER BY created_at DESC LIMIT 100`,
      [req.context.user_id, req.context.tenant_id]
    );
    res.json({ events: rows });
  } catch (err) {
    res.status(500).json({ code: 'SERVER_ERROR', message: err.message });
  }
});

router.get('/audit/all', requireAuth, requireRole('admin', 'super_admin', 'pharmacy_owner', 'auditor'), async (req, res) => {
  try {
    const { user_id, event_type, from_date, to_date, limit = 200 } = req.query;
    const params = [req.context.tenant_id];
    // Columns qualified with aal.* — auth_audit_log JOINs users, which also has
    // tenant_id/user_id/created_at, so unqualified refs are 'column ambiguous' (RC3).
    let where = 'WHERE aal.tenant_id = $1';
    if (user_id)    { params.push(user_id);    where += ` AND aal.user_id = $${params.length}`; }
    if (event_type) { params.push(event_type); where += ` AND aal.event_type = $${params.length}`; }
    if (from_date)  { params.push(from_date);  where += ` AND DATE(aal.created_at) >= $${params.length}`; }
    if (to_date)    { params.push(to_date);    where += ` AND DATE(aal.created_at) <= $${params.length}`; }
    const safeLimit = Math.min(parseInt(limit) || 200, 1000);
    const { rows } = await pool.query(
      `SELECT aal.*, u.email AS user_email, u.role AS user_role
       FROM auth_audit_log aal
       LEFT JOIN users u ON u.id = aal.user_id
       ${where}
       ORDER BY aal.created_at DESC LIMIT $${params.length + 1}`,
      [...params, safeLimit]
    );
    res.json({ events: rows, count: rows.length });
  } catch (err) {
    res.status(500).json({ code: 'SERVER_ERROR', message: err.message });
  }
});

// ─── Accept an invite: the ONLY token-gated way into an EXISTING tenant ─────
// The tenant and email come from the INVITE ROW — never the client. Signup is
// untouched (still mints a fresh tenant); the token proves the invitation.
router.post('/accept-invite', async (req, res) => {
  try {
    const { token, password, first_name, last_name } = req.body || {};
    if (!token || !password) return res.status(400).json({ code: 'VALIDATION_ERROR', message: 'token and password are required' });
    if (String(password).length < 8) return res.status(400).json({ code: 'VALIDATION_ERROR', message: 'password min 8 chars' });
    const { rows: _inv } = await pool.query('SELECT * FROM invites WHERE token = $1 AND deleted_at IS NULL LIMIT 1', [token]);
    if (_inv.length === 0) return res.status(404).json({ code: 'INVITE_NOT_FOUND', message: 'Invite not found' });
    const invite = _inv[0];
    // Spec rule: only the invited email may accept. The account is created WITH
    // the invite's email (enforced by construction); a mismatch is refused loudly.
    const email = String(invite.email || '').toLowerCase();
    if (req.body.email && String(req.body.email).toLowerCase() !== email) {
      return res.status(403).json({ code: 'EMAIL_MISMATCH', message: 'Invite may only be accepted by the invited email' });
    }
    if (invite.status !== 'pending') return res.status(409).json({ code: 'INVITE_NOT_PENDING', message: 'Invite is ' + invite.status });
    if (invite.expires_at && new Date(invite.expires_at) < new Date()) return res.status(410).json({ code: 'INVITE_EXPIRED', message: 'Invite has expired' });
    // Tenant comes from the invite row — the locked identity model holds.
    const tenant_id = invite.tenant_id;
    // Role comes from the admin-authored invite, capped to declared roles.
    const role = (invite.role && VALID_ROLES.includes(invite.role)) ? invite.role : 'member';
    const { rows: existing } = await pool.query('SELECT id FROM users WHERE LOWER(email) = LOWER($1) AND deleted_at IS NULL', [email]);
    if (existing.length > 0) return res.status(409).json({ code: 'EMAIL_TAKEN', message: 'Email already registered' });
    // Seat cap (#6): accepting an invite may not exceed the subscription's seats.
    const { rows: _cap } = await pool.query('SELECT seats AS seats FROM subscriptions WHERE tenant_id = $1 AND deleted_at IS NULL ORDER BY created_at DESC LIMIT 1', [tenant_id]);
    if (_cap.length > 0 && Number.isInteger(_cap[0].seats)) {
      const { rows: _seatCnt } = await pool.query('SELECT COUNT(*)::int AS n FROM users WHERE tenant_id = $1 AND deleted_at IS NULL AND is_active = true', [tenant_id]);
      if (_seatCnt[0].n >= _cap[0].seats) return res.status(409).json({ code: 'SEAT_LIMIT', message: 'Subscription seat limit reached' });
    }
    // Atomically CLAIM the invite first — a concurrent double-accept loses this
    // UPDATE race deterministically (DB-level guard, no SELECT-then-act window).
    const { rows: _claim } = await pool.query("UPDATE invites SET status = 'accepted', updated_at = NOW() WHERE id = $1 AND status = 'pending' RETURNING id", [invite.id]);
    if (_claim.length === 0) return res.status(409).json({ code: 'INVITE_NOT_PENDING', message: 'Invite already used' });
    let user;
    try {
      const password_hash = await hashPassword(password);
      const { rows } = await pool.query(
        `INSERT INTO users (email, password_hash, tenant_id, role, first_name, last_name)
         VALUES ($1,$2,$3,$4,$5,$6) RETURNING id, email, tenant_id, role, first_name, last_name`,
        [email, password_hash, tenant_id, role, first_name || null, last_name || null]
      );
      user = rows[0];
    } catch (err) {
      // Release the claim — a failed create must not burn the invite.
      await pool.query("UPDATE invites SET status = 'pending', updated_at = NOW() WHERE id = $1", [invite.id]);
      throw err;
    }
    logAuthEvent(req, 'invite_accepted', { userId: user.id, tenantId: tenant_id, email, metadata: { invite_id: invite.id, role: user.role } });
    const access_token = signToken({ userId: user.id, tenantId: user.tenant_id, role: user.role, email: user.email });
    const refresh_token = await createRefreshToken(user.id, user.tenant_id);
    const isProd = process.env.NODE_ENV === 'production';
    res.cookie('access_token', access_token, { httpOnly: true, secure: isProd, sameSite: 'strict', maxAge: 15 * 60 * 1000 });
    res.cookie('refresh_token', refresh_token, { httpOnly: true, secure: isProd, sameSite: 'strict', maxAge: 30 * 24 * 60 * 60 * 1000, path: '/auth/refresh' });
    res.status(201).json({ user });
  } catch (err) {
    if (err && err.code === '23505') return res.status(409).json({ code: 'EMAIL_TAKEN', message: 'Email already registered' });
    res.status(500).json({ code: 'SERVER_ERROR', message: err.message });
  }
});

export { router as authRoutes };
